// Recibe el webhook de Retell. Solo procesa el evento call_analyzed
// (call_ended NO trae custom_analysis_data todavia).
const raw = $input.first().json;
const b = raw.body || raw;
const event = b.event;
if (event && event !== 'call_analyzed') {
  return []; // ignora call_started / call_ended
}

const call = b.call || b;
const a = call.call_analysis || {};
const c = a.custom_analysis_data || {};
const dyn = call.retell_llm_dynamic_variables || {};

let estado = 'completada';
const reason = (call.disconnection_reason || '').toLowerCase();
if (a.in_voicemail || /voicemail|machine|answering/.test(reason)) estado = 'buzon';
else if (call.call_status && call.call_status !== 'ended') estado = call.call_status;

return [{
  json: {
    fecha: new Date().toISOString(),
    empresa: dyn.company_name || '',
    telefono: call.to_number || '',
    estado_llamada: estado,
    envia_a_canarias: c.envia_a_canarias ?? '',
    interesado: c.interesado ?? '',
    tipo_mercancia: c.tipo_mercancia ?? '',
    origen_mercancia: c.origen_mercancia ?? '',
    destino_mercancia: c.destino_mercancia ?? '',
    frecuencia_y_volumen: c.frecuencia_y_volumen ?? '',
    operador_actual: c.operador_actual ?? '',
    mejoras_deseadas: c.mejoras_deseadas ?? '',
    es_decisor: c.es_decisor ?? '',
    contacto_decisor: c.contacto_decisor ?? '',
    callback_dia_franja: c.callback_dia_franja ?? '',
    solo_email: c.solo_email ?? '',
    opt_out: c.opt_out ?? '',
    tipo_carga: c.tipo_carga ?? '',
    ruta_oferta: c.ruta_oferta ?? '',
    origen_completo: c.origen_completo ?? '',
    destino_completo: c.destino_completo ?? '',
    tipo_contenedor: c.tipo_contenedor ?? '',
    tipo_servicio: c.tipo_servicio ?? '',
    trincaje_necesario: c.trincaje_necesario ?? '',
    trincaje_quien: c.trincaje_quien ?? '',
    trincaje_material: c.trincaje_material ?? '',
    imo_adr: c.imo_adr ?? '',
    forma_mercancia: c.forma_mercancia ?? '',
    volquete: c.volquete ?? '',
    refrigerado: c.refrigerado ?? '',
    temperatura: c.temperatura ?? '',
    fitosanitaria: c.fitosanitaria ?? '',
    fitosanitaria_tipo: c.fitosanitaria_tipo ?? '',
    multistop: c.multistop ?? '',
    despachante_propio: c.despachante_propio ?? '',
    descarga_hammar: c.descarga_hammar ?? '',
    transbordable: c.transbordable ?? '',
    almacen_logistico: c.almacen_logistico ?? '',
    open_top_tapa: c.open_top_tapa ?? '',
    preferencia_contacto: c.preferencia_contacto ?? '',
    email_contacto: c.email_contacto ?? '',
    solo_grupaje: c.solo_grupaje ?? '',
    grupaje_datos: c.grupaje_datos ?? '',
    resumen: a.call_summary || '',
    grabacion_url: call.recording_url || '',
    closer_status: 'pendiente'
  }
}];
